// Solution
function solve(s) {
  let anchorTags = s.split(' ');
  let result = '';
  for (let tag of anchorTags) {
    if (tag.indexOf('<a') !== -1 && tag.indexOf('href>') !== -1) {
      let hrefIndex = tag.indexOf('href=') + 5;
      if (hrefIndex !== -1 && tag[hrefIndex] === "'" && tag.lastIndexOf("'") > hrefIndex) {
        result += tag;
      }
    }
  }
  return result;
}

